int maxFont(string text, int w, int h, vector<int>& fonts, FontInfo fontInfo) {
        int freq[26] = {0};
        for(auto &ch: text)
            ++freq[ch - 'a'];

        int left = 0, right = fonts.size() - 1;
        while(left < right) {
            int mid = left + (right - left) / 2;
            if(canDisplay(freq, w, h, fontInfo, mid))
                left = mid + 1;
            else
                right = mid;
        }

        return left - 1 == -1 ? -1 : fonts[left - 1];
    }
